import{_ as i,o as a,c as l,ae as o}from"./chunks/framework.DQWLcdWU.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog.md","filePath":"guide/changelog.md"}'),r={name:"guide/changelog.md"};function t(d,e,n,s,c,h){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to Guess‑Rater are documented in this file.</p><p>The project follows <strong>semantic versioning</strong>:</p><ul><li>MAJOR — breaking changes</li><li>MINOR — new features, backward‑compatible</li><li>PATCH — bug fixes, documentation, DX improvements</li></ul><hr><h2 id="v1-4-0" tabindex="-1">v1.4.0 <a class="header-anchor" href="#v1-4-0" aria-label="Permalink to &quot;v1.4.0&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>New list helper: <code>extract()</code><ul><li>returns top N matches from a candidate list</li><li>default return is <code>string[]</code> (values only)</li><li>optional <code>return: &#39;entries&#39;</code> for detailed results (<code>{ value, score, index }</code>)</li><li>optional <code>explain: true</code> when using <code>return: &#39;entries&#39;</code></li><li>supports <code>limit</code> (default 5) and <code>threshold</code> (default 80)</li></ul></li></ul><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>No breaking changes</li><li>Backward compatible</li><li>Feature release focused on list extraction (top matches)</li></ul><hr><h2 id="v1-3-0" tabindex="-1">v1.3.0 <a class="header-anchor" href="#v1-3-0" aria-label="Permalink to &quot;v1.3.0&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>New list helper: <code>filterMatches()</code><ul><li>filters candidates above a threshold</li><li>default return is <code>string[]</code> (values only)</li><li>optional <code>return: &#39;entries&#39;</code> for detailed results (<code>{ value, score, index }</code>)</li><li>optional <code>explain: true</code> when using <code>return: &#39;entries&#39;</code></li></ul></li></ul><h3 id="improved" tabindex="-1">Improved <a class="header-anchor" href="#improved" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Expanded list-matching toolbox without changing existing behaviors</li><li>Consistent “simple-by-default, detailed-on-demand” API style</li></ul><h3 id="notes-1" tabindex="-1">Notes <a class="header-anchor" href="#notes-1" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>No breaking changes</li><li>Backward compatible</li><li>Feature release focused on filtering / list workflows</li></ul><hr><h2 id="v1-2-1" tabindex="-1">v1.2.1 <a class="header-anchor" href="#v1-2-1" aria-label="Permalink to &quot;v1.2.1&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Major TypeScript / IDE DX improvements in <code>index.d.ts</code>: <ul><li>richer inline documentation (hover docs) for core options and behaviors</li><li>clearer option typing for algorithm-specific configuration (<code>jaroWinkler</code>, <code>tokenSort</code>, <code>tokenSet</code>, <code>hybrid</code>)</li></ul></li><li>Overloads for better return type inference: <ul><li><code>rate(..., { explain: true })</code> is inferred as a detailed object</li><li><code>rate(..., { explain: false })</code> / default is inferred as a number</li><li>similar inference improvements for <code>rankCandidates()</code> and <code>findBestMatch()</code> depending on <code>explain</code></li></ul></li></ul><h3 id="improved-1" tabindex="-1">Improved <a class="header-anchor" href="#improved-1" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Autocomplete quality and discoverability of options in VS Code / WebStorm / TS-powered IDEs</li><li>Reduced common mistakes by making return types and option meanings explicit in tooltips</li></ul><h3 id="notes-2" tabindex="-1">Notes <a class="header-anchor" href="#notes-2" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>No runtime changes</li><li>Backward compatible</li><li>DX-only release (types &amp; developer experience)</li></ul><hr><h2 id="v1-2-0" tabindex="-1">v1.2.0 <a class="header-anchor" href="#v1-2-0" aria-label="Permalink to &quot;v1.2.0&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>New optional scoring feature: <code>spaceInsensitive?: boolean</code><ul><li>when enabled, performs an additional comparison pass with all whitespace removed</li><li>keeps the best score between standard vs compact (no-whitespace) comparison</li><li>applies only to character-based algorithms (<code>levenshtein</code>, <code>jaroWinkler</code>)</li><li>does not affect token-based algorithms (<code>tokenSort</code>, <code>tokenSet</code>)</li></ul></li><li>Explain support for <code>spaceInsensitive</code>: <ul><li>when <code>explain: true</code>, details include which pass was selected and related scores</li></ul></li><li>Test coverage for the new feature: <ul><li>boosts char-based algorithms when spaces are missing/extra</li><li>confirms token-based algorithms remain unchanged</li><li>validates hybrid remains coherent and can improve on compact inputs</li></ul></li></ul><h3 id="improved-2" tabindex="-1">Improved <a class="header-anchor" href="#improved-2" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Better matching for compact inputs and &quot;no-spaces&quot; user queries (e.g. <code>iphone14pro</code> vs <code>iphone 14 pro</code>)</li><li>Maintains token semantics by design (non-destructive, opt-in only)</li></ul><h3 id="notes-3" tabindex="-1">Notes <a class="header-anchor" href="#notes-3" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>No breaking changes</li><li>Backward compatible</li><li>Feature release focused on matching robustness</li></ul><hr><h2 id="v1-1-2" tabindex="-1">v1.1.2 <a class="header-anchor" href="#v1-1-2" aria-label="Permalink to &quot;v1.1.2&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Missing TypeScript exports in <code>index.d.ts</code>: <ul><li><code>getSimilarityScore</code></li><li><code>normalizeString</code></li><li><code>getLevenshteinDistance</code></li><li><code>getLevenshteinScore</code></li><li><code>getJaroScore</code></li><li><code>getJaroWinklerScore</code></li><li><code>getTokenSortScore</code></li><li><code>getTokenSetScore</code></li></ul></li><li>Added <code>tokenSort</code> to <code>HybridWeights</code></li><li>New <code>RankedCandidateExplain</code> type for <code>explain: true</code> in <code>rankCandidates</code> and <code>findBestMatch</code></li><li>26 new test cases covering: <ul><li>low-level algorithms</li><li>hybrid mode</li><li><code>createMatcher</code></li><li><code>isMatch</code> with object options</li><li>error cases (invalid type, unknown algorithm)</li></ul></li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Fixed a critical bug where <code>getTokenSetScore(&#39;&#39;, &#39;hello&#39;)</code> returned <code>100</code> instead of <code>0</code> when only one side was empty</li><li>Fixed a bug where using <code>&#39;hybrid&#39;</code> as a sub-algorithm in hybrid weights (for example <code>hybrid: { hybrid: 1 }</code>) produced a cryptic internal error; the error message is now explicit</li></ul><h3 id="improved-3" tabindex="-1">Improved <a class="header-anchor" href="#improved-3" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Optimized Levenshtein performance by replacing the O(n) array copy at each iteration with an O(1) reference swap, reducing the main loop workload significantly</li><li>Increased total test coverage to 39 cases</li></ul><h3 id="notes-4" tabindex="-1">Notes <a class="header-anchor" href="#notes-4" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>No breaking changes</li><li>Backward compatible</li><li>Bug fix, type completeness, performance, and test coverage focused release</li></ul><hr><h2 id="v1-1-1" tabindex="-1">v1.1.1 <a class="header-anchor" href="#v1-1-1" aria-label="Permalink to &quot;v1.1.1&quot;">​</a></h2><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>TypeScript declaration files (<code>.d.ts</code>)</li><li>Full IDE autocomplete support</li><li>Inline documentation for options and algorithms</li></ul><h3 id="improved-4" tabindex="-1">Improved <a class="header-anchor" href="#improved-4" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Developer experience in VS Code and similar editors</li><li>Safer configuration via typed options</li></ul><h3 id="notes-5" tabindex="-1">Notes <a class="header-anchor" href="#notes-5" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>No runtime changes</li><li>Backward compatible</li><li>Documentation and DX focused release</li></ul><hr><h2 id="v1-1-0" tabindex="-1">v1.1.0 <a class="header-anchor" href="#v1-1-0" aria-label="Permalink to &quot;v1.1.0&quot;">​</a></h2><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Modular matching engine</li><li>Multiple algorithms: <ul><li>Levenshtein</li><li>Jaro‑Winkler</li><li>TokenSort</li><li>TokenSet</li><li>Hybrid</li></ul></li><li>Normalization pipeline</li><li>Hybrid weighted scoring</li><li>Ranking helpers: <ul><li><code>rankCandidates</code></li><li><code>findBestMatch</code></li></ul></li><li><code>createMatcher</code> for reusable configurations</li><li>Explain mode for debugging</li></ul><h3 id="improved-5" tabindex="-1">Improved <a class="header-anchor" href="#improved-5" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Matching accuracy on noisy inputs</li><li>Flexibility across domains</li></ul><h3 id="notes-6" tabindex="-1">Notes <a class="header-anchor" href="#notes-6" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>Backward compatible with previous API</li><li>Major internal refactor</li></ul><hr><h2 id="v1-0-1" tabindex="-1">v1.0.1 <a class="header-anchor" href="#v1-0-1" aria-label="Permalink to &quot;v1.0.1&quot;">​</a></h2><h3 id="initial-release" tabindex="-1">Initial release <a class="header-anchor" href="#initial-release" aria-label="Permalink to &quot;Initial release&quot;">​</a></h3><ul><li>Basic string similarity scoring</li><li>Levenshtein algorithm</li><li>Simple normalization</li><li>Minimal API surface</li></ul><hr><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>Guess‑Rater is an <strong>open‑source project</strong> and contributions are welcome.</p><p>Anyone can:</p><ul><li>use the library freely</li><li>fork the repository</li><li>experiment with new ideas</li><li>propose improvements</li></ul><h3 id="contribution-workflow" tabindex="-1">Contribution workflow <a class="header-anchor" href="#contribution-workflow" aria-label="Permalink to &quot;Contribution workflow&quot;">​</a></h3><ol><li>Fork the repository on GitHub</li><li>Create a branch in your fork</li><li>Make your changes</li><li>Open a Pull Request (PR)</li><li>The PR is reviewed thoroughly</li><li>The PR is either merged, requested for changes, or rejected</li></ol><p>All Pull Requests are reviewed <strong>in depth</strong> to ensure:</p><ul><li>code quality</li><li>correctness</li><li>consistency with the project philosophy</li><li>backward compatibility</li><li>proper documentation when required</li></ul><p>Not all contributions will be merged, and that is OK. Every proposal is reviewed with care and respect.</p><hr><h2 id="future-plans" tabindex="-1">Future plans <a class="header-anchor" href="#future-plans" aria-label="Permalink to &quot;Future plans&quot;">​</a></h2><p>Planned improvements may include:</p><ul><li>additional algorithms</li><li>domain presets (names, products, addresses)</li><li>performance optimizations</li><li>more recipes and examples</li><li>extended documentation</li><li>community‑driven enhancements</li></ul>',78)])])}const m=i(r,[["render",t]]);export{p as __pageData,m as default};
